/* =============================================================================
   AURA ALPHA -- Developer Portal
   API key management, interactive docs, code examples, rate limits, webhooks.
   Route: /developer-portal
   ============================================================================= */
import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import AnimatedPage, { staggerContainer, staggerItem } from '../components/AnimatedPage';
import usePageTitle from '../hooks/usePageTitle';
import useIsMobile from '../hooks/useIsMobile';
import { api, apiPost, apiDelete } from '../utils/api';
import s from './DeveloperPortalPage.module.css';

// -- Design tokens (kept for dynamic color references) -------------------------
import { tokens } from '../styles/tokens';
const C = {
  textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  textMuted: tokens.color.textMuted, green: tokens.color.green, red: tokens.color.red,
  blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};

const fadeIn = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0, transition: { duration: 0.25 } },
  exit: { opacity: 0, y: -8, transition: { duration: 0.15 } },
};

// -- Available scopes --------------------------------------------------------
const SCOPES = [
  { id: 'strategies:read', label: 'Strategies', desc: 'Read strategy catalogue and scores' },
  { id: 'positions:read', label: 'Positions', desc: 'Read open positions' },
  { id: 'orders:read', label: 'Orders', desc: 'Read order history and fills' },
  { id: 'backtests:read', label: 'Backtests', desc: 'Read backtest results' },
  { id: 'data:read', label: 'Market Data', desc: 'Read OHLCV candles' },
  { id: 'risk:read', label: 'Risk', desc: 'Read risk exposure metrics' },
  { id: 'telemetry:read', label: 'Telemetry', desc: 'Read bot heartbeats and status' },
  { id: 'signals:read', label: 'Signals', desc: 'Read live scanner signals' },
  { id: 'system:read', label: 'System', desc: 'Read system health' },
];

const WEBHOOK_EVENTS = [
  'alert.triggered', 'daily.summary', 'position.closed',
  'position.opened', 'signal.new', 'trade.executed',
];

// -- Code block component ----------------------------------------------------
function CodeBlock({ code, language = 'text' }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    navigator.clipboard.writeText(code).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };
  return (
    <div className={s.codeBlock}>
      <div className={s.codeBlockHeader}>
        <span className={s.codeBlockLang}>{language}</span>
        <button onClick={handleCopy} className={copied ? s.copyBtnCopied : s.copyBtnDefault}>
          {copied ? 'Copied' : 'Copy'}
        </button>
      </div>
      <pre className={s.codeBlockPre}>{code}</pre>
    </div>
  );
}

// -- Endpoint Row ------------------------------------------------------------
function EndpointRow({ ep }) {
  const [expanded, setExpanded] = useState(false);
  const methodColor = ep.method === 'GET' ? C.green : ep.method === 'POST' ? C.blue : ep.method === 'DELETE' ? C.red : C.amber;
  return (
    <div className={s.endpointRow}>
      <button onClick={() => setExpanded(!expanded)} className={s.endpointBtn}>
        <span className={s.methodBadge} style={{ color: methodColor, background: methodColor + '15' }}>
          {ep.method}
        </span>
        <span className={s.endpointPath}>{ep.path}</span>
        <span className={s.endpointToggle}>{expanded ? '-' : '+'}</span>
      </button>
      {expanded && (
        <motion.div {...fadeIn} className={s.endpointDetail}>
          <p className={s.endpointDesc}>{ep.description}</p>
          {ep.scopes && (
            <div className={s.endpointScopes}>
              {ep.scopes.map(sc => (
                <span key={sc} className={s.endpointScopeBadge}>{sc}</span>
              ))}
            </div>
          )}
          <div className={s.endpointCurl}>
            <CodeBlock language="curl" code={`curl -H "X-API-Key: YOUR_KEY" https://auraalpha.cc${ep.path}`} />
          </div>
        </motion.div>
      )}
    </div>
  );
}

// -- Main Component ----------------------------------------------------------
export default function DeveloperPortalPage() {
  usePageTitle('Developer Portal');
  const isMobile = useIsMobile();

  const [tab, setTab] = useState('keys'); // keys | docs | webhooks
  const [apiKeys, setApiKeys] = useState([]);
  const [docs, setDocs] = useState(null);
  const [webhooks, setWebhooks] = useState([]);
  const [usageData, setUsageData] = useState(null);
  const [selectedKeyId, setSelectedKeyId] = useState(null);

  // Create key form
  const [newKeyName, setNewKeyName] = useState('');
  const [newKeyScopes, setNewKeyScopes] = useState([]);
  const [newKeyExpiry, setNewKeyExpiry] = useState('');
  const [createdKey, setCreatedKey] = useState(null);
  const [creating, setCreating] = useState(false);

  // Webhook form
  const [whUrl, setWhUrl] = useState('');
  const [whEvents, setWhEvents] = useState([]);
  const [creatingWh, setCreatingWh] = useState(false);
  const [whSecret, setWhSecret] = useState(null);

  const [error, setError] = useState('');

  // Load data
  useEffect(() => {
    refreshKeys();
    api('/developer/docs').then(d => { if (d) setDocs(d); }).catch(() => {});
    refreshWebhooks();
  }, []);

  const refreshKeys = useCallback(() => {
    api('/developer/keys').then(d => setApiKeys(d || [])).catch(() => setApiKeys([]));
  }, []);

  const refreshWebhooks = useCallback(() => {
    api('/developer/webhooks').then(d => setWebhooks(d || [])).catch(() => setWebhooks([]));
  }, []);

  async function createKey() {
    if (!newKeyName.trim()) { setError('Key name is required'); return; }
    if (newKeyScopes.length === 0) { setError('Select at least one scope'); return; }
    setCreating(true);
    setError('');
    try {
      const body = { name: newKeyName, scopes: newKeyScopes };
      if (newKeyExpiry) body.expires_in_days = parseInt(newKeyExpiry);
      const res = await apiPost('/developer/keys', body);
      setCreatedKey(res?.api_key);
      refreshKeys();
      setNewKeyName('');
      setNewKeyScopes([]);
      setNewKeyExpiry('');
    } catch (e) {
      setError(e?.message || 'Failed to create key');
    } finally {
      setCreating(false);
    }
  }

  async function revokeKey(keyId) {
    try {
      await apiDelete(`/developer/keys/${keyId}`);
      refreshKeys();
      if (selectedKeyId === keyId) { setSelectedKeyId(null); setUsageData(null); }
    } catch (e) {
      setError(e?.message || 'Failed to revoke key');
    }
  }

  async function loadUsage(keyId) {
    setSelectedKeyId(keyId);
    try {
      const data = await api(`/developer/keys/${keyId}/usage`);
      setUsageData(data);
    } catch {
      setUsageData(null);
    }
  }

  async function createWebhook() {
    if (!whUrl.trim()) { setError('URL is required'); return; }
    if (whEvents.length === 0) { setError('Select at least one event'); return; }
    setCreatingWh(true);
    setError('');
    try {
      const res = await apiPost('/developer/webhooks', { url: whUrl, events: whEvents });
      setWhSecret(res.secret);
      refreshWebhooks();
      setWhUrl('');
      setWhEvents([]);
    } catch (e) {
      setError(e?.message || 'Failed to create webhook');
    } finally {
      setCreatingWh(false);
    }
  }

  async function deleteWebhook(id) {
    try {
      await apiDelete(`/developer/webhooks/${id}`);
      refreshWebhooks();
    } catch (e) {
      setError(e?.message || 'Failed to delete webhook');
    }
  }

  async function testWebhook(id) {
    try {
      const res = await apiPost(`/developer/webhooks/${id}/test`, {});
      alert(`Test result: HTTP ${res.status_code} (${res.latency_ms?.toFixed(0)}ms)`);
    } catch (e) {
      setError(e?.message || 'Test failed');
    }
  }

  function toggleScope(scope) {
    setNewKeyScopes(prev => prev.includes(scope) ? prev.filter(s => s !== scope) : [...prev, scope]);
  }
  function toggleWhEvent(evt) {
    setWhEvents(prev => prev.includes(evt) ? prev.filter(e => e !== evt) : [...prev, evt]);
  }

  const tabs = [
    { id: 'keys', label: 'API Keys' },
    { id: 'docs', label: 'API Docs' },
    { id: 'webhooks', label: 'Webhooks' },
  ];

  return (
    <AnimatedPage>
      <div className={isMobile ? s.pageRootMobile : s.pageRoot}>
        {/* Header */}
        <div className={s.header}>
          <h1 className={s.headerTitle}>Developer Portal</h1>
          <div className={s.versionBadge}>Public API v1.0</div>
        </div>

        {/* Tab bar */}
        <div className={s.tabBar}>
          {tabs.map(t => (
            <button key={t.id} onClick={() => setTab(t.id)}
              className={tab === t.id ? s.tabBtnActive : s.tabBtn}>
              {t.label}
            </button>
          ))}
        </div>

        {error && (
          <div className={s.errorBanner}>
            {error}
            <button onClick={() => setError('')} className={s.errorClose} aria-label="Dismiss error">x</button>
          </div>
        )}

        <AnimatePresence mode="wait">
          {/* -- API Keys Tab ------------------------------------------------- */}
          {tab === 'keys' && (
            <motion.div key="keys" {...fadeIn}>
              {/* Create key form */}
              <div className={s.card}>
                <h3 className={s.cardTitle}>Create API Key</h3>
                <div className={isMobile ? s.inputRowMobile : s.inputRowDesktop}>
                  <input value={newKeyName} onChange={e => setNewKeyName(e.target.value)}
                    placeholder="Key name (e.g. My Trading Bot)" className={s.input} />
                  <input type="number" value={newKeyExpiry} onChange={e => setNewKeyExpiry(e.target.value)}
                    placeholder="Expiry days" className={s.input} min={1} />
                </div>
                <div className={s.fieldLabel}>Permissions</div>
                <div className={s.toggleRow}>
                  {SCOPES.map(sc => (
                    <button key={sc.id} onClick={() => toggleScope(sc.id)} title={sc.desc}
                      className={newKeyScopes.includes(sc.id) ? s.toggleBtnOnBlue : s.toggleBtnOff}>
                      {sc.label}
                    </button>
                  ))}
                </div>
                <button onClick={createKey} disabled={creating} className={s.createKeyBtn}>
                  {creating ? 'Creating...' : 'Generate Key'}
                </button>

                {/* Show newly created key */}
                {createdKey && (
                  <motion.div {...fadeIn} className={s.secretBanner}>
                    <div className={s.secretLabel}>
                      Save this key now -- it will not be shown again!
                    </div>
                    <CodeBlock language="key" code={createdKey} />
                    <button onClick={() => setCreatedKey(null)} className={s.dismissBtn}>Dismiss</button>
                  </motion.div>
                )}
              </div>

              {/* Existing keys */}
              <div className={s.cardNoPad}>
                <div className={s.listHeader}>Your API Keys ({apiKeys.length})</div>
                {apiKeys.length === 0 ? (
                  <div className={s.emptyState}>No API keys. Create one above to get started.</div>
                ) : (
                  <div>
                    {apiKeys.map(k => (
                      <div key={k.id} className={s.keyRow}>
                        <div className={s.keyInfo}>
                          <div className={s.keyName}>{k.name}</div>
                          <div className={s.keyMeta}>
                            <span className={s.keyPrefix}>aura_{k.prefix}_****</span>
                            <span className={k.active ? s.statusActive : s.statusRevoked}>
                              {k.active ? 'Active' : 'Revoked'}
                            </span>
                            {k.last_used && <span className={s.lastUsed}>Last used: {k.last_used?.slice(0, 16)}</span>}
                          </div>
                          <div className={s.scopeList}>
                            {(k.scopes || []).map(sc => (
                              <span key={sc} className={s.scopeBadge}>{sc}</span>
                            ))}
                          </div>
                        </div>
                        <div className={s.keyActions}>
                          <button onClick={() => loadUsage(k.id)} className={s.usageBtn}>Usage</button>
                          {k.active && (
                            <button onClick={() => revokeKey(k.id)} className={s.revokeBtn}>Revoke</button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Usage detail */}
              {usageData && selectedKeyId && (
                <motion.div {...fadeIn} className={s.usagePanel}>
                  <div className={s.usagePanelHeader}>
                    <h3 className={s.usagePanelTitle}>Usage Stats</h3>
                    <button onClick={() => { setUsageData(null); setSelectedKeyId(null); }} className={s.usageClose} aria-label="Close usage panel">x</button>
                  </div>
                  <div className={isMobile ? s.usageGridMobile : s.usageGridDesktop}>
                    <div className={s.usageStatCard}>
                      <div className={s.usageStatLabel}>Error Rate</div>
                      <div className={s.usageStatValue} style={{ color: usageData.error_rate > 0.05 ? C.red : C.green }}>
                        {((usageData.error_rate || 0) * 100).toFixed(1)}%
                      </div>
                    </div>
                    <div className={s.usageStatCard}>
                      <div className={s.usageStatLabel}>Top Endpoint</div>
                      <div className={s.usageStatValueSm}>
                        {usageData.top_endpoints?.[0]?.endpoint || '--'}
                      </div>
                    </div>
                    <div className={s.usageStatCard}>
                      <div className={s.usageStatLabel}>Total Calls (30d)</div>
                      <div className={s.usageStatValue} style={{ color: C.blue }}>
                        {Object.values(usageData.calls_per_day || {}).reduce((a, b) => a + b, 0).toLocaleString()}
                      </div>
                    </div>
                  </div>
                  {/* Daily calls mini chart */}
                  {usageData.calls_per_day && Object.keys(usageData.calls_per_day).length > 0 && (
                    <div>
                      <div className={s.chartSectionLabel}>Daily Calls (last 30 days)</div>
                      <div className={s.chartBars}>
                        {Object.entries(usageData.calls_per_day).sort(([a], [b]) => a.localeCompare(b)).slice(-30).map(([day, count]) => {
                          const max = Math.max(...Object.values(usageData.calls_per_day)) || 1;
                          const h = Math.max(4, (count / max) * 50);
                          return (
                            <div key={day} title={`${day}: ${count}`} className={s.chartBar} style={{ height: h }} />
                          );
                        })}
                      </div>
                    </div>
                  )}
                  {/* Top endpoints table */}
                  {usageData.top_endpoints?.length > 0 && (
                    <div className={s.topEndpoints}>
                      <div className={s.chartSectionLabel}>Top Endpoints</div>
                      {usageData.top_endpoints.map((ep, i) => (
                        <div key={i} className={s.topEndpointRow}>
                          <span className={s.topEndpointPath}>{ep.endpoint}</span>
                          <span className={s.topEndpointCount}>{ep.count}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </motion.div>
              )}
            </motion.div>
          )}

          {/* -- API Docs Tab ------------------------------------------------- */}
          {tab === 'docs' && (
            <motion.div key="docs" {...fadeIn}>
              {/* Auth info */}
              <div className={s.card}>
                <h3 className={s.cardTitleSm}>Authentication</h3>
                <p className={s.authText}>
                  All API requests require an <strong className={s.authHighlight}>X-API-Key</strong> header.
                  Keys are scoped to specific permissions and rate-limited per minute.
                  Use <code className={s.inlineCode}>/api/v1/*</code> endpoints.
                </p>
                <div className={isMobile ? s.infoGridMobile : s.infoGridDesktop}>
                  <div className={s.infoCell}>
                    <div className={s.infoCellLabel}>Base URL</div>
                    <div className={s.infoCellValue} style={{ color: C.blue }}>https://auraalpha.cc/api/v1</div>
                  </div>
                  <div className={s.infoCell}>
                    <div className={s.infoCellLabel}>Auth Header</div>
                    <div className={s.infoCellValue} style={{ color: C.amber }}>X-API-Key</div>
                  </div>
                  <div className={s.infoCell}>
                    <div className={s.infoCellLabel}>Rate Limit</div>
                    <div className={s.infoCellValue} style={{ color: C.green }}>100 req/min (default)</div>
                  </div>
                </div>
              </div>

              {/* Code examples */}
              <div className={s.card}>
                <h3 className={s.cardTitle}>Quick Start</h3>
                <div className={s.codeExamples}>
                  <CodeBlock language="python" code={docs?.code_examples?.python || 'import requests\n\nheaders = {"X-API-Key": "aura_xxxx_xxxxxxxx"}\nresp = requests.get("https://auraalpha.cc/api/v1/strategies", headers=headers)\nprint(resp.json())'} />
                  <CodeBlock language="javascript" code={docs?.code_examples?.javascript || 'const resp = await fetch("https://auraalpha.cc/api/v1/strategies", {\n  headers: { "X-API-Key": "aura_xxxx_xxxxxxxx" }\n});\nconst data = await resp.json();'} />
                  <CodeBlock language="curl" code={docs?.code_examples?.curl || 'curl -H "X-API-Key: aura_xxxx_xxxxxxxx" https://auraalpha.cc/api/v1/strategies'} />
                </div>
              </div>

              {/* Endpoints list */}
              <div className={s.cardNoPad}>
                <div className={s.listHeader}>Endpoints ({docs?.endpoints?.length || 0})</div>
                {(docs?.endpoints || []).map((ep, i) => (
                  <EndpointRow key={i} ep={ep} />
                ))}
              </div>

              {/* Available scopes */}
              <div className={s.cardMt}>
                <h3 className={s.cardTitleSm}>Available Scopes</h3>
                <div className={isMobile ? s.scopesGridMobile : s.scopesGridDesktop}>
                  {SCOPES.map(sc => (
                    <div key={sc.id} className={s.scopeRow}>
                      <span className={s.scopeId}>{sc.id}</span>
                      <span className={s.scopeDesc}>{sc.desc}</span>
                    </div>
                  ))}
                </div>
              </div>
            </motion.div>
          )}

          {/* -- Webhooks Tab ------------------------------------------------- */}
          {tab === 'webhooks' && (
            <motion.div key="webhooks" {...fadeIn}>
              {/* Create webhook */}
              <div className={s.card}>
                <h3 className={s.cardTitle}>Register Webhook</h3>
                <input value={whUrl} onChange={e => setWhUrl(e.target.value)}
                  placeholder="https://your-server.com/webhook" className={s.inputFull} />
                <div className={s.fieldLabel}>Events</div>
                <div className={s.toggleRow}>
                  {WEBHOOK_EVENTS.map(evt => (
                    <button key={evt} onClick={() => toggleWhEvent(evt)}
                      className={whEvents.includes(evt) ? s.toggleBtnOnCyan : s.toggleBtnOffMono}>
                      {evt}
                    </button>
                  ))}
                </div>
                <button onClick={createWebhook} disabled={creatingWh} className={s.createWhBtn}>
                  {creatingWh ? 'Creating...' : 'Register Webhook'}
                </button>

                {whSecret && (
                  <motion.div {...fadeIn} className={s.secretBanner}>
                    <div className={s.secretLabel}>Webhook signing secret (save this now):</div>
                    <CodeBlock language="secret" code={whSecret} />
                    <button onClick={() => setWhSecret(null)} className={s.dismissBtn}>Dismiss</button>
                  </motion.div>
                )}
              </div>

              {/* Existing webhooks */}
              <div className={s.cardNoPad}>
                <div className={s.listHeader}>Your Webhooks ({webhooks.length})</div>
                {webhooks.length === 0 ? (
                  <div className={s.emptyState}>No webhooks registered.</div>
                ) : (
                  <div>
                    {webhooks.map(wh => (
                      <div key={wh.id} className={s.whRow}>
                        <div className={s.whInfo}>
                          <div className={s.whUrl}>{wh.url}</div>
                          <div className={s.whMeta}>
                            <span className={wh.active ? s.whActive : s.whDisabled}>
                              {wh.active ? 'Active' : 'Disabled'}
                            </span>
                            {wh.failure_count > 0 && (
                              <span className={s.whFailures}>{wh.failure_count} failures</span>
                            )}
                            {wh.last_triggered_at && (
                              <span className={s.whLastTriggered}>Last: {wh.last_triggered_at?.slice(0, 16)}</span>
                            )}
                          </div>
                          <div className={s.whEvents}>
                            {(wh.events || []).map(e => (
                              <span key={e} className={s.whEventBadge}>{e}</span>
                            ))}
                          </div>
                        </div>
                        <div className={s.whActions}>
                          <button onClick={() => testWebhook(wh.id)} className={s.testBtn}>Test</button>
                          <button onClick={() => deleteWebhook(wh.id)} className={s.deleteBtn}>Delete</button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Webhook signature info */}
              <div className={s.cardMt}>
                <h3 className={s.cardTitleSm}>Verifying Webhooks</h3>
                <p className={s.verifyText}>
                  All webhook deliveries include an <code className={s.inlineCode}>X-Webhook-Signature</code> header
                  containing an HMAC-SHA256 signature of the request body using your webhook secret.
                </p>
                <CodeBlock language="python" code={`import hmac, hashlib\n\ndef verify(body: bytes, signature: str, secret: str) -> bool:\n    expected = hmac.new(secret.encode(), body, hashlib.sha256).hexdigest()\n    return hmac.compare_digest(expected, signature)`} />
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </AnimatedPage>
  );
}
